import type { RequestHandler } from "express";
import type { Env } from "../../config/env.js";
import { HttpError } from "../../lib/httpError.js";
import { httpErrorFromZod } from "../../lib/httpErrorFromZod.js";
import { presignBodySchema } from "./schemas.js";
import * as uploadsService from "./service.js";

function requireTenantContext(req: Parameters<RequestHandler>[0]) {
  const tenantId = req.tenantId;
  const creatorId = req.creatorId;
  if (!tenantId || !creatorId) {
    return null;
  }
  return { tenantId, creatorId };
}

export const presign: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const parsed = presignBodySchema.safeParse(req.body);
    if (!parsed.success) {
      next(httpErrorFromZod(parsed.error));
      return;
    }
    const env = req.app.get("env") as Env;
    const out = await uploadsService.createPresignedPut(
      env,
      ctx.tenantId,
      ctx.creatorId,
      parsed.data
    );
    res.status(201).json(out);
  } catch (e) {
    next(e);
  }
};

import { apiFetch, readApiErrorMessage } from "./api";

export type PresignPutResult =
  | { ok: true; publicUrl: string; contentType: string }
  | { ok: false; message: string };

export async function presignAndPutFile(file: File): Promise<PresignPutResult> {
  const presign = await apiFetch("/uploads/presign", {
    method: "POST",
    body: JSON.stringify({
      fileName: file.name,
      contentType: file.type || "application/octet-stream"
    })
  });
  const pBody = await presign.json().catch(() => ({}));
  if (!presign.ok) {
    return { ok: false, message: readApiErrorMessage(pBody, "Presign failed") };
  }
  const p = pBody as { uploadUrl?: string; publicUrl?: string; contentType?: string };
  if (!p.uploadUrl || !p.publicUrl) {
    return { ok: false, message: "Invalid presign response" };
  }
  const put = await fetch(p.uploadUrl, {
    method: "PUT",
    body: file,
    headers: {
      "Content-Type": (p.contentType ?? file.type) || "application/octet-stream"
    }
  });
  if (!put.ok) {
    return { ok: false, message: "Upload to storage failed" };
  }
  return {
    ok: true,
    publicUrl: p.publicUrl,
    contentType: (p.contentType ?? file.type) || "application/octet-stream"
  };
}

